import os
from groq import AsyncGroq

class LocalAgentConfig:
    pass

class ChatResponseStream:
    def __init__(self, response_stream):
        self.response_stream = response_stream

    def __aiter__(self):
        return self

    async def __anext__(self):
        try:
            chunk = await self.response_stream.__anext__()
            if chunk.choices and chunk.choices[0].delta.content:
                return chunk.choices[0].delta.content
            else:
                return ""
        except StopAsyncIteration:
            raise StopAsyncIteration

class Agent:
    def __init__(self, config=None):
        self.config = config
        api_key = os.environ.get("GROQ_API_KEY")
        if not api_key:
            raise ValueError("GROQ_API_KEY environment variable is missing. Cannot initialize groq.")
        self.client = AsyncGroq(api_key=api_key)
        self.chat_history = [
            {"role": "system", "content": "You are Antigravity, a helpful AI assistant running locally on a user's Mac. Keep responses concise."}
        ]

    async def __aenter__(self):
        return self

    async def __aexit__(self, exc_type, exc_val, exc_tb):
        pass

    async def chat(self, message: str):
        self.chat_history.append({"role": "user", "content": message})
        response_stream = await self.client.chat.completions.create(
            model="llama-3.1-8b-instant",
            messages=self.chat_history,
            stream=True
        )
        return ChatResponseStream(response_stream)
